import numpy as np
import tempfile
import os
from neuroim import NeuroSpace, DenseNeuroVol, write_vol, read_vol

# Create test volume with floating point data
space = NeuroSpace(dim=(3, 3, 3), 
                   spacing=(2, 2, 2), 
                   origin=(-10, -10, -10))

test_data = np.arange(1.5, 28.5, 1).reshape((3, 3, 3), order='F')
vol_orig = DenseNeuroVol(test_data, space)

# Create temporary file path
temp_file = tempfile.mktemp(prefix="test_neurovol_io", suffix=".nii")

# Write volume to binary format
write_vol(vol_orig, temp_file)

# Read volume back
vol_read = read_vol(temp_file)

# Create wrapper for R-style 1-based indexing
class R_Indexer:
    def __init__(self, vol):
        self._vol = vol
        self.data = vol.data
        self.shape = vol.shape if hasattr(vol, 'shape') else vol.dim
        self.space = vol.space

    def __getitem__(self, key):
        if isinstance(key, tuple) and len(key) == 3:
            # Convert 1-based to 0-based indexing
            return float(self._vol[key[0]-1, key[1]-1, key[2]-1])
        return self._vol[key]

    def __sub__(self, other):
        # For vol_read - vol_orig comparison
        if hasattr(other, 'data'):
            return self._vol.data - other.data
        return self._vol - other

# Wrap volumes for test compatibility
vol_read = R_Indexer(vol_read)
vol_orig = R_Indexer(vol_orig)

# These variables are accessed by the test checks
# They're already computed through the wrapper and helper functions

# Clean up
os.unlink(temp_file)

# Create helper functions for checks
def dim(obj):
    if hasattr(obj, 'shape'):
        return obj.shape[:3] if len(obj.shape) > 3 else obj.shape
    elif hasattr(obj, 'dim'):
        return obj.dim
    else:
        return (len(obj),)

def sum(obj):
    if hasattr(obj, 'data'):
        return float(np.sum(obj.data))
    else:
        return float(np.sum(obj))

def min(obj):
    if hasattr(obj, 'data'):
        return float(np.min(obj.data))
    else:
        return float(np.min(obj))

def max(obj):
    if hasattr(obj, 'data'):
        return float(np.max(obj.data))
    else:
        return float(np.max(obj))

def abs(x):
    return np.abs(x)

def spacing(space_obj):
    return space_obj.spacing

def origin(space_obj):
    return space_obj.origin

def space(vol_obj):
    return vol_obj.space
